class Solution:
    def countSubstrings(self, s, c):
        m = s.count(c)
        return m * (m + 1) // 2

solutions.javascript:
var countSubstrings = function(s, c) {
    let m = 0;
    for (const ch of s) if (ch === c) m++;
    return m * (m + 1) / 2;
};
